// Express.js middleware: Authorization check
async function authorizeWorkspaceAccess(req, res, next) {
  const { workspace_id } = req.params;
  const userId = req.user.id; // From JWT

  // Check if user belongs to this workspace
  const membership = await db.WorkspaceMember.findOne({
    where: {
      workspace_id: workspace_id,
      user_id: userId
    }
  });

  if (!membership) {
    return res.status(403).json({
      error: 'Access denied: You are not a member of this workspace'
    });
  }

  next();
}

// Apply middleware to ALL workspace routes (v1 AND v2)
app.use('/api/v1/workspaces/:workspace_id', authorizeWorkspaceAccess);
app.use('/api/v2/workspaces/:workspace_id', authorizeWorkspaceAccess);
